/*
 * expf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly expf  (test_expf_opt.elf)
 *   2. Linked with toolchain's default expf        (test_expf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc = 0.0f;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += expf(vx);
#else
    float r = expf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

#ifndef EN_PERF
/* ------------------------------------------------------------------ */
/* Representative 100-point analytic test                             */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf: expf(+Inf) = +Inf */
    emit_u(0xff800000u);  /* -Inf: expf(-Inf) = 0 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                /* smallest normal: 2^-126 = 0x00800000 */
    emit(-FLT_MIN);
    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    emit_u(0x7f7fffffu);          /* FLT_MAX: expf overflows */
    emit(-FLT_MAX);               /* expf(-FLT_MAX) = 0 (underflow) */
    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3f7fffffu);          /* one ULP below 1.0 */
    emit(1.0f);
    emit_u(0x3f800001u);          /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);          /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);          /* a few ULPs above 1.0 */
    emit(-1.0f);
    emit_u(0xbf7fffffu);          /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);          /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3f000000u);          /* 0.5 */
    emit_u(0x3effffffu);          /* one ULP below 0.5 */
    emit_u(0x3f000001u);          /* one ULP above 0.5 */
    emit_u(0x40000000u);          /* 2.0 */
    emit_u(0x3fffffffu);          /* one ULP below 2.0 */
    emit_u(0x40000001u);          /* one ULP above 2.0 */

    /* --- Section 6: Mathematical constants / key values (14) --- */
    emit_u(0x3f317218u);          /* ln(2) as float: expf(ln2) = 2.0 */
    emit_u(0xbf317218u);          /* -ln(2): expf(-ln2) = 0.5 */
    emit_u(0x3f317217u);          /* one ULP below ln(2) */
    emit_u(0x3f317219u);          /* one ULP above ln(2) */
    emit(2.302585093f);           /* ln(10): expf(ln10) = 10.0 */
    emit(0.5f);                   /* expf(0.5) = sqrt(e) */
    emit(-0.5f);
    emit(2.0f);                   /* expf(2) = e^2 */
    emit(-2.0f);
    emit(0.1f);
    emit(-0.1f);
    emit(0.30102999566f);         /* log10(2) */
    emit(0.43429448190f);         /* 1/ln(10) */
    emit(2.71828182845f);         /* e itself: expf(e) = e^e */

    /* --- Section 7: Overflow / underflow thresholds (10) --- */
    emit_u(0x42b17218u);          /* overflow threshold ~88.7229 */
    emit_u(0x42b17217u);          /* one ULP below overflow threshold */
    emit_u(0x42b17219u);          /* one ULP above overflow threshold -> +Inf */
    emit_u(0xc2b17218u);          /* -overflow threshold: deep underflow */
    emit_u(0xc2cff1b5u);          /* underflow threshold ~-103.9 */
    emit_u(0xc2cff1b4u);          /* one ULP above underflow threshold */
    emit_u(0xc2cff1b6u);          /* one ULP below underflow threshold -> 0 */
    emit(88.0f);                  /* just below overflow */
    emit(89.0f);                  /* just above overflow -> +Inf */
    emit(-104.0f);                /* below underflow -> 0 */

    /* --- Section 8: ULP neighbors of exact result boundaries (9) --- */
    emit_u(0x42aeac50u);          /* exact underflow boundary ~87.3365 */
    emit_u(0x42aeac4fu);          /* one ULP below */
    emit_u(0x42aeac51u);          /* one ULP above */
    emit(10.0f);
    emit(-10.0f);
    emit(50.0f);
    emit(-50.0f);
    emit(80.0f);
    emit(-80.0f);

    /* --- Section 9: Small-argument fast-path boundaries (8) --- */
    emit_u(0x35000000u);          /* 2^-21: very small positive */
    emit_u(0xb5000000u);          /* 2^-21 negative */
    emit_u(0x33800000u);          /* 2^-24: at mantissa precision boundary */
    emit_u(0xb3800000u);          /* 2^-24 negative */
    emit_u(0x36800000u);          /* 2^-18 */
    emit_u(0xb6800000u);          /* 2^-18 negative */
    emit(1.0e-20f);               /* extremely small: expf ~ 1.0 */
    emit(-1.0e-20f);

    /* --- Section 10: Polynomial branch and hard cases (26) --- */
    /* Powers of 2 inputs */
    emit(4.0f);
    emit(-4.0f);
    emit(8.0f);
    emit(-8.0f);
    emit(16.0f);
    emit(-16.0f);
    emit(32.0f);
    emit(-32.0f);
    emit(64.0f);
    emit(-64.0f);
    /* ULP neighbors of ln(2)/2 (argument reduction midpoint) */
    emit_u(0x3eb17218u);          /* ln(2)/2 ~0.3466 */
    emit_u(0x3eb17217u);          /* one ULP below ln(2)/2 */
    emit_u(0x3eb17219u);          /* one ULP above ln(2)/2 */
    /* ULP neighbors of ln(2)*1.5 */
    emit_u(0x3f96a850u);          /* 1.5*ln(2) ~1.0397 */
    emit_u(0x3f96a84fu);          /* one ULP below */
    emit_u(0x3f96a851u);          /* one ULP above */
    /* Values where result is exactly representable or near-exact */
    emit_u(0x42d4e000u);          /* ~105.4375, near overflow */
    emit_u(0xc2d40000u);          /* near underflow */
    emit(0.25f);
    emit(-0.25f);
    emit(3.0f);
    emit(-3.0f);
    emit(5.0f);
    emit(-5.0f);
    emit(100.0f);                 /* expf(100) = +Inf */
    emit(-100.0f);                /* expf(-100) = 0 (subnormal) */
}

/* 7. Sweep [-10, 10] in 200 steps */
static void test_sweep(void)
{
    float lo = -10.0f;
    float hi = 10.0f;
    int nsteps = 200;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (float)i * step);
}

/* 8. Sample [0, 1] every 4194304 ULP (~1000 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf result: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

